private function _generate_app_rsa_keys()
{
$config=array(
'private_key_bits'=> 2048,
'private_key_type'=> OPENSSL_KEYTYPE_RSA,
);
$result=array('server_pem'=> '', 'server_key'=> '', 'client_pem'=> '', 'client_key'=> '');
$res=@openssl_pkey_new($config);
if ($res && openssl_pkey_export($res, $privKey)) {
$pubKeyDetails=openssl_pkey_get_details($res);
if ($pubKeyDetails && isset($pubKeyDetails['key'])) {
$result['server_key']=$privKey;
$result['server_pem']=$pubKeyDetails['key'];
}
}
$res=@openssl_pkey_new($config);
if ($res && openssl_pkey_export($res, $privKey)) {
$pubKeyDetails=openssl_pkey_get_details($res);
if ($pubKeyDetails && isset($pubKeyDetails['key'])) {
$result['client_key']=$privKey;
$result['client_pem']=$pubKeyDetails['key'];
}
}
return $result;
}
